struct stat_double { double mystery; double a; double b; };

void who_am_i(stat_double &data) {
  if (data.a > data.b) data.mystery = data.a;
  else                data.mystery = data.b;
}

// caller: d.a = 7, d.b = 3 -> d.mystery = 7

void who_am_i(stat_double &data) {
  data.mystery = data.a + data.b;
}
// caller: d.a = 4, d.b = 6 -> d.mystery = 10

struct stat_double { double mystery; double numbers[5]; };

void who_am_i(stat_double &data) {
  data.mystery = data.numbers[0];
  for (int i = 1; i < 5; i++) {
    if (data.numbers[i] > data.mystery) {
      data.mystery = data.numbers[i];
    }
  }
}
// caller: numbers = {3, 9, 1, 7, 4} -> mystery = 9

void who_am_i(stat_double &data) {
  data.mystery = data.numbers[0];
  for (int i = 1; i < 5; i++) {
    if (data.numbers[i] < data.mystery) {
      data.mystery = data.numbers[i];
    }
  }
}
// caller: numbers = {3, 9, 1, 7, 4} -> mystery = 1

void who_am_i(stat_double &data) {
  data.mystery = 0;
  for (int i = 0; i < 5; i++) {
    data.mystery = data.mystery + data.numbers[i];
  }
}
// caller: numbers = {3, 9, 1, 7, 4} -> mystery = 24

void who_am_i(stat_double &data) {
  data.mystery = 0;
  for (int i = 0; i < 5; i++) {
    if (data.numbers[i] > 5) data.mystery = data.mystery + 1;
  }
}
// caller: numbers = {3, 9, 1, 7, 8} -> mystery = 3

void who_am_i(stat_double &data) {
  data.mystery = -1;
  for (int i = 0; i < 5; i++) {
    if (data.numbers[i] > 0) {
      data.mystery = data.numbers[i];
      break;
    }
  }
}
// caller: numbers = {0, -2, 7, 4, 1} -> mystery = 7

void who_am_i(stat_double &data) {
  data.mystery = 0;
  for (int i = 0; i < 5; i++) {
    data.mystery = data.mystery + data.numbers[i];
  }
  data.mystery = data.mystery / 5;
}
// caller: numbers = {3, 9, 1, 7, 4} -> mystery = 4.8 (double / int)

void who_am_i(stat_double &data) {
  data.mystery = data.a * data.b;
}
// caller: d.a = 5, d.b = 7 -> d.mystery = 35

// SUBTLE: missing & means caller is untouched.
void who_am_i(stat_double data) {   // <-- no &
  data.mystery = 99;
}
// caller: d.mystery = 0 -> after call: d.mystery STILL 0

void who_am_i(stat_double &data) {
  data.mystery = data.a;
}
// caller: d.a = 42 -> d.mystery = 42

void who_am_i(stat_double &data) {
  double x = data.a;
  double y = data.b;
  data.mystery = x + y;
}
// caller: d.a = 3, d.b = 5 -> x=3, y=5, mystery = 8

double helper(double x, double y) {
  return x + y;
}

void who_am_i(stat_double &data) {
  data.mystery = helper(data.a, data.b);
}
// caller: d.a = 3, d.b = 4 -> helper returns 7 -> mystery = 7

double compute(double a) {
  double temp = a * 2;
  return temp;
}

void who_am_i(stat_double &data) {
  data.mystery = compute(data.a);
  // temp no longer exists here
}
// caller: d.a = 5 -> temp=10 (dies at return) -> mystery = 10

void who_am_i(stat_double &data) {
  data.mystery = data.a;
  data.a = 0;
}
// caller: d.a = 7 -> d.mystery = 7, d.a = 0 (both persist via &)

void who_am_i(stat_double &data) {
  data.numbers[2] = 99;
  data.mystery = data.numbers[2];
}
// caller: numbers[2] was 1 -> becomes 99, mystery = 99

double add_one(double x) {
  return x + 1;
}

void who_am_i(stat_double &data) {
  double r = add_one(data.a);
  data.mystery = add_one(r);
}
// caller: d.a = 5 -> r = 6 -> mystery = 7

void who_am_i(stat_double &data) {
  data.a = data.a + 1;
  data.b = data.a * 2;
  data.mystery = data.b;
}
// caller: d.a = 3 -> d.a = 4, d.b = 8, d.mystery = 8

